// parallel/test-runner-cli-concurrency where a test file remains locked
// while the tmp directory is being removed.

const tmpDir = path.join(__dirname, '.tmp-concurrency');
const testFile = path.join(tmpDir, 'test-2.cjs');

function setupTmpDir() {
  if (fs.existsSync(tmpDir)) {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  }
  fs.mkdirSync(tmpDir, { recursive: true });
}

function writeLockedTestFile() {
  const content = `
    const { test } = require('node:test');
    const fs = require('node:fs');
    const path = require('node:path');

    // Keep a file descriptor open for the duration of the test run to
    // simulate Windows keeping the file locked while the parent process
    // tries to delete the directory.
    const fd = fs.openSync(__filename, 'r');

    test('long running test to keep file open', (t, done) => {
      setTimeout(() => {
        fs.closeSync(fd);
        done();
      }, 2000);
    });
  `;
  fs.writeFileSync(testFile, content);
}

function runNodeTestWithConcurrencyTwo() {
  // Run `node --test` on the tmp directory with concurrency 2.
  // On Windows this can lead to EBUSY when the parent tries to clean up
  // the directory while the child process still has the file open.
  const result = spawnSync(process.execPath, [
    '--test-concurrency=2',
    '--test',
    tmpDir,
  ], {
    encoding: 'utf8'
  });

  console.log('child stdout:\n', result.stdout);
  console.error('child stderr:\n', result.stderr);
  console.log('child status:', result.status);
}

